// Determine AM or PM session and build idempotency key
const now = new Date();
const hour = now.getUTCHours();
const session = hour < 12 ? 'am' : 'pm';
const dateStr = now.toISOString().split('T')[0];
const idempotencyKey = `linkedin-monitor:${dateStr}:${session}`;

return [{
  json: {
    dateStr,
    session,
    hour,
    idempotencyKey
  }
}];

// Merge and filter RSS items from all 5 feeds (last 24 hours)
const now = new Date();
const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const feedSources = [
  { name: 'IASME', topics: 'Cyber Essentials, CE Plus, IASME Governance' },
  { name: 'NCSC', topics: 'Cyber threats, guidance, supply chain, SME security' },
  { name: 'ICO', topics: 'Data protection, GDPR, enforcement, SME guidance' },
  { name: 'Def Stan', topics: 'Defence standards, Def Stan 05-138, procurement' },
  { name: 'ADS Group', topics: 'Aerospace, defence, security industry' }
];

// Collect all items from all input branches
const allItems = [];
for (let branchIdx = 0; branchIdx < 5; branchIdx++) {
  const sourceName = feedSources[branchIdx].name;
  const sourceTopics = feedSources[branchIdx].topics;
  try {
    const branchItems = $input.all(branchIdx) || [];
    for (const item of branchItems) {
      const pubDate = item.json.pubDate ? new Date(item.json.pubDate) : 
                      item.json.isoDate ? new Date(item.json.isoDate) :
                      item.json.date ? new Date(item.json.date) : null;

      if (pubDate && pubDate >= twentyFourHoursAgo) {
        const ageHours = (now.getTime() - pubDate.getTime()) / (1000 * 60 * 60);
        const urgency = ageHours < 2 ? 'High' : ageHours < 6 ? 'Medium' : 'Low';

        allItems.push({
          source: sourceName,
          topics: sourceTopics,
          title: item.json.title || 'Untitled',
          link: item.json.link || item.json.url || '',
          description: (item.json.contentSnippet || item.json.description || item.json.summary || '').substring(0, 500),
          pubDate: pubDate.toISOString(),
          ageHours: Math.round(ageHours * 10) / 10,
          urgency
        });
      }
    }
  } catch (e) {
    // Feed may have failed or returned no items — skip gracefully
  }
}

// Sort by urgency (High first), then by age
allItems.sort((a, b) => {
  const urgencyOrder = { High: 0, Medium: 1, Low: 2 };
  return (urgencyOrder[a.urgency] - urgencyOrder[b.urgency]) || (a.ageHours - b.ageHours);
});

return [{
  json: {
    itemCount: allItems.length,
    items: allItems,
    feedSummary: allItems.length > 0
      ? allItems.map((item, i) => `${i + 1}. [${item.urgency}] ${item.source}: "${item.title}"\n   URL: ${item.link}\n   Published: ${item.pubDate} (${item.ageHours}h ago)\n   Summary: ${item.description.substring(0, 200)}`).join('\n\n')
      : 'No new items found in the last 24 hours across all feeds.'
  }
}];

// Parse GLM-5 response and format notification
const response = $input.item.json;
const session = $('Prepare Session Info').item.json.session;
const dateStr = $('Prepare Session Info').item.json.dateStr;
const itemCount = $('Filter Last 24h Items').item.json.itemCount;

// Extract text from Anthropic Messages API response
let commentContent = '';
if (response.content && Array.isArray(response.content)) {
  commentContent = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('\n');
} else if (typeof response === 'string') {
  commentContent = response;
}

const inputTokens = response.usage?.input_tokens || 0;
const outputTokens = response.usage?.output_tokens || 0;

const notificationText = `*LinkedIn RSS Monitor Complete* (${session.toUpperCase()}, ${dateStr})\n\nFeeds checked: IASME, NCSC, ICO, Def Stan, ADS Group\nNew items found: ${itemCount}\nTokens: ${inputTokens} in / ${outputTokens} out\n\n${commentContent.substring(0, 3000)}${commentContent.length > 3000 ? '\n\n_[Truncated]_' : ''}`;

return [{
  json: {
    dateStr,
    session,
    itemCount,
    commentContent,
    inputTokens,
    outputTokens,
    notificationText
  }
}];
